#target illustrator
/* Illustrator Data Merge engine v1.0.0
   Fill an Adobe Illustrator template from data — one output file per record.
   The Illustrator equivalent of a data merge: profile a template once, then stamp out
   a populated file per record, swapping only the text (and, optionally, linked images)
   you point it at, while preserving every font, color, and the layout.

   Reads   ~/.datamerge/job.jsxinc   (defines global DATAMERGE_JOB)
   Writes  ~/.datamerge/result.json

   Modes:
     "discover" - dump a template's text frames + named linked images so a profile can be built.
     "build"    - apply optional master fixes, then for each record copy the template,
                  populate mapped fields, save, snapshot-verify, optionally render a PNG proof.
     "render"   - re-export PNG previews for listed files.

   Edits are content-only and style-preserving. Color, type styling, position, and layout
   are never changed. All record knowledge lives in the job, not in this engine. */
(function () {
  app.userInteractionLevel = UserInteractionLevel.DONTDISPLAYALERTS;
  var HOME = Folder("~").fsName;
  var BASE = HOME + "/.datamerge";

  function readFile(p){ var f=new File(p); f.encoding="UTF-8"; if(!f.exists) return null; f.open("r"); var s=f.read(); f.close(); return s; }
  function writeFile(p,s){ var f=new File(p); f.encoding="UTF-8"; f.open("w"); f.write(s); f.close(); }

  /* ---- ES3-safe JSON stringify ---- */
  function esc(s){ s=String(s); var o=""; for(var i=0;i<s.length;i++){ var c=s.charAt(i), k=s.charCodeAt(i);
    if(c=='"')o+='\\"'; else if(c=='\\')o+='\\\\'; else if(c=='\n')o+='\\n'; else if(c=='\r')o+='\\r'; else if(c=='\t')o+='\\t';
    else if(k<32)o+='\\u'+('0000'+k.toString(16)).slice(-4); else o+=c; } return o; }
  function J(v){
    if(v===null||v===undefined) return "null";
    var t=typeof v;
    if(t=="number"||t=="boolean") return String(v);
    if(t=="string") return '"'+esc(v)+'"';
    if(v instanceof Array){ var a=[]; for(var i=0;i<v.length;i++) a.push(J(v[i])); return "["+a.join(",")+"]"; }
    var p=[]; for(var k in v){ if(v.hasOwnProperty(k)) p.push('"'+esc(k)+'":'+J(v[k])); } return "{"+p.join(",")+"}";
  }

  /* ---- style-preserving text edit primitives ----
     Each edits only the target characters in place so surrounding font runs are kept. */
  function replaceSub(f, oldS, newS){
    var s=String(f.contents); var idx=s.indexOf(oldS);
    if(idx<0) return "NOTFOUND";
    f.characters[idx].contents=String(newS);
    var at=idx+String(newS).length, n=String(oldS).length-1;
    for(var r=0;r<n;r++){ f.characters[at].remove(); }
    return "OK";
  }
  function removeSub(f, sub){
    var s=String(f.contents); var idx=s.indexOf(sub);
    if(idx<0) return "NOTFOUND";
    for(var r=0;r<String(sub).length;r++){ f.characters[idx].remove(); }
    return "OK";
  }
  function bodyAfter(f, prefix, body){
    var s=String(f.contents); var pi=s.indexOf(prefix);
    if(pi<0) return "NOPREFIX";
    var start=pi+String(prefix).length, len=f.textRange.characters.length;
    if(start>=len){ f.characters[len-1].contents=String(f.characters[len-1].contents)+String(body); return "OK"; }
    f.characters[start].contents=String(body);
    var removeAt=start+String(body).length;
    while(f.textRange.characters.length>removeAt){ f.characters[removeAt].remove(); }
    return "OK";
  }

  /* ---- per-record linked image swap (relink, refit into the same box) ----
     The template must contain a LINKED placed image; name it in the Layers panel and
     map that name in the profile. Embedded images cannot be relinked. */
  function findPlaced(doc, fld){
    var items=doc.placedItems;
    if(fld.name!=null){ for(var i=0;i<items.length;i++){ if(String(items[i].name)===String(fld.name)) return items[i]; } }
    if(fld.index!=null && fld.index<items.length) return items[fld.index];
    return null;
  }
  function relinkImage(doc, fld, path){
    var t=findPlaced(doc, fld);
    if(t===null) return "NOIMG";
    var nf=new File(path);
    if(!nf.exists) return "FILEMISSING";
    var oldW=t.width, oldH=t.height, oldPos=t.position; // position = [left, top]
    t.file=nf;
    if(fld.fit!==false){
      if(fld.preserveAspect){
        var nw=t.width, nh=t.height, sc=Math.min(oldW/nw, oldH/nh);
        t.width=nw*sc; t.height=nh*sc;
        t.position=[oldPos[0]+(oldW-t.width)/2, oldPos[1]-(oldH-t.height)/2];
      } else { t.width=oldW; t.height=oldH; t.position=oldPos; }
    }
    return "OK";
  }

  function fontRuns(f){
    var chars=f.textRange.characters, runs=[], cur=null, str="";
    for(var k=0;k<chars.length;k++){ var fn; try{ fn=chars[k].characterAttributes.textFont.name; }catch(e){ fn="?"; }
      if(fn!==cur){ if(cur!==null) runs.push({font:cur,text:str}); cur=fn; str=String(chars[k].contents); }
      else str+=String(chars[k].contents); }
    if(cur!==null) runs.push({font:cur,text:str});
    return runs;
  }

  function applyField(doc, fld, val){
    var m=fld.method;
    if(m=="image")     return relinkImage(doc, fld, val);
    var f=doc.textFrames[fld.frame];
    if(m=="sub")       return replaceSub(f, fld.from, val);
    if(m=="removeSub") return removeSub(f, (fld.sub!=null?fld.sub:fld.from));
    if(m=="bodyAfter") return bodyAfter(f, fld.prefix, val);
    if(m=="contents"){ f.contents=String(val); return "OK"; }
    return "BADMETHOD";
  }

  function renderDoc(d, dir, scale){
    var folder=new Folder(dir); if(!folder.exists) folder.create();
    var opts=new ExportOptionsPNG24();
    opts.antiAliasing=true; opts.transparency=false; opts.artBoardClipping=true;
    opts.horizontalScale=scale; opts.verticalScale=scale;
    var safe=String(d.name).replace(/\.ai$/i,"").replace(/[^A-Za-z0-9]/g,"_");
    var dest=new File(dir+"/"+safe+".png");
    d.exportFile(dest, ExportType.PNG24, opts);
    return { png:dest.fsName, exists:dest.exists };
  }

  /* ---- load job ---- */
  var src=readFile(BASE+"/job.jsxinc");
  if(src===null){ writeFile(BASE+"/result.json", J({ok:false,error:"missing job.jsxinc"})); return; }
  eval(src);
  var JOB=DATAMERGE_JOB;
  var result={ ok:true, mode:JOB.mode, ts:(new Date()).toString() };

  try{
    if(JOB.mode=="discover"){
      var d=app.open(new File(JOB.template));
      var tf=d.textFrames, frames=[];
      for(var i=0;i<tf.length;i++){
        var f=tf[i], pos; try{ pos=f.position; }catch(e){ pos=[0,0]; }
        frames.push({ i:i, contents:String(f.contents), x:Math.round(pos[0]), y:Math.round(pos[1]), runs:fontRuns(f) });
      }
      var pls=d.placedItems, images=[];
      for(var pi2=0; pi2<pls.length; pi2++){ images.push({ index:pi2, name:String(pls[pi2].name), file:(function(){ try{return String(pls[pi2].file);}catch(e){return "";} })() }); }
      result.template=JOB.template; result.frameCount=tf.length; result.frames=frames; result.images=images;
      d.close(SaveOptions.DONOTSAVECHANGES);
      writeFile(BASE+"/result.json", J(result)); return;
    }

    if(JOB.mode=="build"){
      result.template=JOB.template; result.outputDir=JOB.outputDir; result.masterFixes=[]; result.products=[];
      var _od=new Folder(JOB.outputDir); if(!_od.exists) _od.create();
      if(JOB.masterFixes && JOB.masterFixes.length){
        var md=app.open(new File(JOB.template)); 
        for(var mf=0; mf<JOB.masterFixes.length; mf++){
          var fix=JOB.masterFixes[mf]; var to=(fix.to!=null?fix.to:"");
          result.masterFixes.push({ frame:fix.frame, method:fix.method, result:applyField(md, fix, to) });
        }
        md.save(); md.close(SaveOptions.DONOTSAVECHANGES);
        writeFile(BASE+"/result.json", J(result));
        if(JOB.fixMasterOnly){ return; }
      }
      var fresh=(JOB.freshCopy!==false);
      var renderDir=JOB.outputDir+"/"+(JOB.renderSubdir||"_previews");
      var templateFile=new File(JOB.template);
      var recs = JOB.records || JOB.products || [];
      for(var p=0;p<recs.length;p++){
        var prod=recs[p], rec={ file:prod.file }, d2;
        try{
          var destPath=JOB.outputDir+"/"+prod.file; var df=new File(destPath);
          if(fresh){ if(df.exists) df.remove(); templateFile.copy(df); }
          d2=app.open(new File(destPath));
          var flags=[], snap={};
          for(var fi=0; fi<JOB.profile.fields.length; fi++){
            var fld=JOB.profile.fields[fi];
            var val=(prod.values?prod.values[fld.key]:null);
            if((val===undefined||val===null) && fld.method!="removeSub"){ continue; }
            var rr=applyField(d2, fld, val);
            if(rr!=="OK") flags.push(fld.key+":"+rr);
          }
          for(var si=0; si<JOB.profile.fields.length; si++){
            var sf=JOB.profile.fields[si];
            if(sf.method=="image"){ var pit=findPlaced(d2, sf); snap[sf.key]="[image] "+(pit?(function(){try{return String(pit.file);}catch(e){return "linked";}})():"NOIMG"); }
            else { snap[sf.key]=String(d2.textFrames[sf.frame].contents); }
          }
          d2.save();
          rec.status=(flags.length?"FLAGS":"OK"); rec.flags=flags; rec.snapshot=snap;
          if(JOB.render){ rec.render=renderDoc(d2, renderDir, JOB.renderScale||300); }
          d2.close(SaveOptions.DONOTSAVECHANGES);
        }catch(ep){ rec.status="ERROR"; rec.error=String(ep); try{ if(d2) d2.close(SaveOptions.DONOTSAVECHANGES); }catch(e2){} }
        result.products.push(rec);
        writeFile(BASE+"/result.json", J(result));
      }
      writeFile(BASE+"/result.json", J(result)); return;
    }

    if(JOB.mode=="render"){
      result.outputDir=JOB.outputDir; result.products=[];
      var rdir=JOB.outputDir+"/"+(JOB.renderSubdir||"_previews");
      var recs2 = JOB.records || JOB.products || [];
      for(var rp=0; rp<recs2.length; rp++){
        var pf=recs2[rp].file, rrec={ file:pf }, rd;
        try{ rd=app.open(new File(JOB.outputDir+"/"+pf)); rrec.render=renderDoc(rd, rdir, JOB.renderScale||300); rd.close(SaveOptions.DONOTSAVECHANGES); }
        catch(er){ rrec.error=String(er); try{ if(rd) rd.close(SaveOptions.DONOTSAVECHANGES); }catch(e3){} }
        result.products.push(rrec);
        writeFile(BASE+"/result.json", J(result));
      }
      writeFile(BASE+"/result.json", J(result)); return;
    }

    result.ok=false; result.error="unknown mode: "+JOB.mode;
    writeFile(BASE+"/result.json", J(result));
  }catch(e){
    result.ok=false; result.error=String(e);
    writeFile(BASE+"/result.json", J(result));
  }
})();

#!/usr/bin/env node
/* Illustrator Data Merge report generator: turns ~/.datamerge/result.json into a
   self-contained, dark-themed report.html. Auto-run by run.sh. */
const fs = require('fs'); const os = require('os'); const path = require('path');
const BASE = path.join(os.homedir(), '.datamerge');
const RES = path.join(BASE, 'result.json');
const OUT = path.join(BASE, 'report.html');
function esc(s){ return String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }
let r; try { r = JSON.parse(fs.readFileSync(RES,'utf8')); } catch(e){ fs.writeFileSync(OUT,'<h1>No result.json</h1>'); process.exit(0); }
const css = `
:root{color-scheme:dark}
body{background:#0e0f12;color:#e7e9ee;font:14px/1.5 -apple-system,Segoe UI,Roboto,sans-serif;margin:0;padding:32px}
h1{font-size:20px;margin:0 0 4px} .sub{color:#9aa0ad;margin:0 0 24px;font-size:13px}
.card{background:#16181d;border:1px solid #262a33;border-radius:10px;padding:16px 18px;margin:0 0 14px}
.row{display:flex;align-items:center;gap:10px;flex-wrap:wrap}
.pill{font-size:12px;font-weight:700;padding:2px 9px;border-radius:999px}
.ok{background:#10331f;color:#5fd38a;border:1px solid #1d5e39}
.flags{background:#3a2f10;color:#e7c15f;border:1px solid #6b551d}
.err{background:#3a1414;color:#f08a8a;border:1px solid #6b1d1d}
.name{font-weight:600;font-size:15px}
table{border-collapse:collapse;width:100%;margin-top:10px;font-size:12.5px}
td,th{border-bottom:1px solid #23262e;padding:4px 8px;text-align:left;vertical-align:top}
th{color:#9aa0ad;font-weight:600}
code{color:#cdd3df;background:#0b0c0f;padding:1px 5px;border-radius:4px}
.thumb{margin-top:10px;max-width:320px;border:1px solid #2a2e37;border-radius:6px;background:#fff}
.muted{color:#9aa0ad}
`;
let body = '';
body += `<h1>Illustrator Data Merge &mdash; ${esc(r.mode||'')} report</h1>`;
body += `<p class="sub">${esc(r.ts||'')}${r.template?(' &middot; template: <code>'+esc(r.template)+'</code>'):''}${r.outputDir?(' &middot; out: <code>'+esc(r.outputDir)+'</code>'):''}</p>`;
if(r.ok===false){ body += `<div class="card"><span class="pill err">ERROR</span> <code>${esc(r.error)}</code></div>`; }
if(r.mode==='discover' && r.frames){
  body += `<div class="card"><div class="row"><span class="name">${r.frameCount} text frames</span><span class="muted">map fields to frame indices using contents + font runs</span></div>`;
  body += `<table><tr><th>#</th><th>x,y</th><th>contents</th><th>font runs</th></tr>`;
  for(const f of r.frames){ const runs=(f.runs||[]).map(x=>`${esc(x.font)}=[${esc(x.text)}]`).join('<br>');
    body += `<tr><td><code>${f.i}</code></td><td class="muted">${f.x},${f.y}</td><td>${esc(f.contents)}</td><td class="muted">${runs}</td></tr>`; }
  body += `</table></div>`;
  if(r.images && r.images.length){
    body += `<div class="card"><div class="name">${r.images.length} linked image(s)</div><table><tr><th>index</th><th>name</th><th>file</th></tr>`;
    for(const im of r.images){ body += `<tr><td><code>${im.index}</code></td><td>${esc(im.name)||'<span class="muted">(unnamed)</span>'}</td><td class="muted">${esc(im.file)}</td></tr>`; }
    body += `</table></div>`;
  }
}
if(r.masterFixes && r.masterFixes.length){
  body += `<div class="card"><div class="name">Template fixes</div><table><tr><th>frame</th><th>method</th><th>result</th></tr>`;
  for(const m of r.masterFixes){ body += `<tr><td><code>${esc(m.frame)}</code></td><td>${esc(m.method)}</td><td>${esc(m.result)}</td></tr>`; }
  body += `</table></div>`;
}
if(r.products && r.products.length){
  let okN=0, flagN=0, errN=0;
  for(const p of r.products){ if(p.status==='OK')okN++; else if(p.status==='FLAGS')flagN++; else if(p.status==='ERROR'||p.error)errN++; }
  body += `<div class="card"><div class="row"><span class="name">${r.products.length} files</span><span class="pill ok">${okN} ok</span>`;
  if(flagN) body += `<span class="pill flags">${flagN} flags</span>`;
  if(errN) body += `<span class="pill err">${errN} error</span>`;
  body += `</div></div>`;
  for(const p of r.products){
    const cls = p.status==='OK'?'ok':(p.status==='FLAGS'?'flags':'err');
    body += `<div class="card"><div class="row"><span class="name">${esc(p.file)}</span><span class="pill ${cls}">${esc(p.status||(p.error?'ERROR':'OK'))}</span></div>`;
    if(p.flags && p.flags.length) body += `<p class="muted">flags: ${p.flags.map(esc).join(', ')}</p>`;
    if(p.error) body += `<p class="muted">${esc(p.error)}</p>`;
    if(p.snapshot){ body += `<table><tr><th>field</th><th>value</th></tr>`;
      for(const k of Object.keys(p.snapshot)){ body += `<tr><td class="muted">${esc(k)}</td><td>${esc(p.snapshot[k])}</td></tr>`; } body += `</table>`; }
    if(p.render && p.render.exists && p.render.png){ body += `<div><img class="thumb" src="file://${esc(p.render.png)}"></div>`; }
  }
}
fs.writeFileSync(OUT, `<!doctype html><meta charset="utf-8"><title>Illustrator Data Merge report</title><style>${css}</style><body>${body}</body>`);
